  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '城市ID',
  `name` varchar(50) NOT NULL COMMENT '城市名称',
  `level` varchar(20) DEFAULT NULL COMMENT '城市等级：一线城市/新一线城市/二线城市/三线城市',
  `sort` int(11) DEFAULT '0' COMMENT '排序值，数字越小越靠前',
