#
# Structure for table "fa_leads"
#

DROP TABLE IF EXISTS `fa_leads`;
CREATE TABLE `fa_leads` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '线索ID',
  `lead_no` varchar(50) NOT NULL COMMENT '线索编号',
  `raw_content` text NOT NULL COMMENT '原始录入文本',
  `city_id` int(11) DEFAULT NULL COMMENT '所属城市ID',
  `district_id` int(11) DEFAULT NULL COMMENT '所属区域ID',
  `grade` varchar(50) DEFAULT NULL COMMENT '年级',
  `subject` varchar(50) DEFAULT NULL COMMENT '科目',
  `phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `contact_name` varchar(50) DEFAULT NULL COMMENT '联系人姓名',
  `assigned_admin_id` int(11) DEFAULT NULL COMMENT '指派客服ID',
  `status` enum('待跟进','跟进中','已发单','已出单','不需要','无效') DEFAULT '待跟进' COMMENT '跟进状态',
  `tutor_content` text COMMENT '发单内容（状态为已发单时必填）',
  `tutor_title` varchar(500) DEFAULT NULL COMMENT '家教标题',
  `invalid_image` varchar(255) DEFAULT NULL COMMENT '无效图片路径（状态为无效时必填）',
  `info_fee` decimal(10,2) DEFAULT NULL COMMENT '信息费金额（状态为已出单时填写）',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `creator_admin_id` int(11) DEFAULT NULL COMMENT '创建人管理员ID',
  `channel` enum('美团','58同城','表单','渠道生源','其他') DEFAULT '其他' COMMENT '线索渠道',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_lead_no` (`lead_no`),
  KEY `idx_status` (`status`),
  KEY `idx_assigned_admin` (`assigned_admin_id`),
  KEY `idx_city_id` (`city_id`),
  KEY `idx_create_time` (`create_time`),
  KEY `idx_channel` (`channel`),
  KEY `idx_info_fee` (`info_fee`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COMMENT='线索主表';

#
# Data for table "fa_leads"
#

INSERT INTO `fa_leads` VALUES (1,'0117','0117 深圳\n学生年级\t三年级\n性别\t\n男\n辅导科目\t数学\n授课地址\t崇文花园\n预计开始辅导时间\t2025-11-02\n时间安排及频率\t一周一次\n学生情况\t中等\n对老师要求\t有耐心，讲解通俗易懂孩子容易接受\n愿意支付一个小时的薪酬范围\t150\n学生姓名\t\n陈柏丞\n手机\t\n13798288793\n是否选择近期试课\t\n是，近期就需要安排上课',196,NULL,'','','13798288793','',6,'跟进中',NULL,NULL,NULL,NULL,'2025-11-02 04:55:52','2026-03-11 15:04:27',1,'表单'),(2,'11029836','联系人称呼：\t张竹林\t联系人电话：\t13316561121\t辅导区域：\t深圳市龙岗区深圳市龙岗区布吉大芬地铁站附近\n学生年级：\t高三\t学生性别：\t男生\n辅导科目：\t数学\t其他科目：\t\n学生情况：\t\n可辅导时间：\t周六下午14点\t辅导次数：\t一周一次\t每次辅导时长：\t2小时（推荐）\n愿付时薪：\t200-300元\t老师性别要求：\t男老师\t要求说明：\t需毕业985或211本科以上',196,1851,'高中','数学','13316561121','',6,'跟进中',NULL,NULL,NULL,NULL,'2025-11-02 05:50:08','2026-03-11 15:04:18',1,'表单'),(3,'0115','0115   18018701975  南山育才三中附近小六小一语文，男孩小六，女孩小一，分开一对一，一周1-2次，女老专业老师  420/2小时   需要短信发微信让家长加  谈好了',196,NULL,'小学','语文','18018701975','',6,'跟进中',NULL,NULL,NULL,NULL,'2025-11-02 05:51:17','2026-03-11 15:04:14',1,'其他'),(4,'0114','0114  微信 18127955929，王先生，电话 136 4028 3699， 广州番禺，小组课大概 4-7 个小孩，幼儿到小学阶段，400/两个小时，试课也正常付费，要求专业老师',194,1832,'幼儿','','18127955929','',6,'跟进中',NULL,NULL,NULL,NULL,'2025-11-02 05:52:21','2026-03-11 15:02:53',1,'其他'),(5,'0112','0112，18520729466 陈女士，初二数学。女孩。基础比较差。广州天河，大学生 180-220 两个小时，专职老师 400-450 两个小时，要发短信加微信。手机号搜不到微信，指派给宇辰',194,1829,'初中','数学','18520729466','',6,'无效',NULL,NULL,'/uploads/images/202512/20251202112832_692e5ce0dc710.png',NULL,'2025-11-02 05:59:44','2026-03-11 15:03:59',1,'其他'),(6,'0101','0101  13590229418 钟先生，宝安壹方城小四作业，男孩，周一到周五 6-8 点，每次两个小时，女老师。报价发单',196,1850,'小学','','13590229418','',34,'跟进中',NULL,NULL,NULL,NULL,'2025-11-02 06:03:17','2025-12-02 13:29:04',1,'其他'),(7,'11027171','学生年级\t高三\n性别\t\n女\n辅导科目\t数学物理化学\n授课地址\t宝安福永凤凰南区\n预计开始辅导时间\t2025-11-01\n时间安排及频率\t一周二次\n学生情况\t理科\n对老师要求\t善于引导，鼓励孩子\n愿意支付一个小时的薪酬范围\t100-200-300不等，看学生的进步\n学生姓名\t\n黄乙芙\n手机\t\n13480872313\n是否选择近期试课\t\n是，近期就需要安排上课',196,1850,'高中','数学','13480872313','',6,'已发单',NULL,'支持多选复制家教内容',NULL,NULL,'2025-11-02 06:06:59','2026-03-11 15:04:05',1,'表单');

#
# Structure for table "fa_mini_program_config"
#

DROP TABLE IF EXISTS `fa_mini_program_config`;
CREATE TABLE `fa_mini_program_config` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `platform` varchar(20) NOT NULL COMMENT '平台: wechat/alipay',
  `app_id` varchar(128) NOT NULL DEFAULT '' COMMENT '小程序AppID',
  `mini_program_name` varchar(100) NOT NULL DEFAULT '' COMMENT '小程序名称',
  `app_secret_enc` text COMMENT '加密后的AppSecret',
  `env_version` varchar(20) NOT NULL DEFAULT 'release' COMMENT '环境: develop/trial/release',
  `is_enabled` tinyint(1) NOT NULL DEFAULT '1' COMMENT '启用状态:1启用0禁用',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认配置:1是0否',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_platform_appid` (`platform`,`app_id`),
  KEY `idx_platform_enabled` (`platform`,`is_enabled`),
  KEY `idx_platform_default` (`platform`,`is_default`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COMMENT='小程序多端配置';

