#
# Structure for table "fa_seo_config"
#

DROP TABLE IF EXISTS `fa_seo_config`;
CREATE TABLE `fa_seo_config` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `page_type` varchar(50) NOT NULL COMMENT '页面类型：home,teachers,teacher-detail,search等',
  `page_title` varchar(200) DEFAULT NULL COMMENT '页面标题',
  `page_keywords` varchar(500) DEFAULT NULL COMMENT '页面关键词',
  `page_description` varchar(1000) DEFAULT NULL COMMENT '页面描述',
  `og_title` varchar(200) DEFAULT NULL COMMENT 'Open Graph标题',
  `og_description` varchar(1000) DEFAULT NULL COMMENT 'Open Graph描述',
  `og_image` varchar(500) DEFAULT NULL COMMENT 'Open Graph图片',
  `canonical_url` varchar(500) DEFAULT NULL COMMENT '规范URL',
  `robots` varchar(100) DEFAULT 'index,follow' COMMENT 'robots指令',
  `sitemap_priority` decimal(2,1) DEFAULT '0.8' COMMENT '站点地图优先级(0.1-1.0)',
  `sitemap_changefreq` varchar(20) DEFAULT 'weekly' COMMENT '站点地图更新频率',
  `is_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用：1启用 0禁用',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_page_type` (`page_type`),
  KEY `idx_is_enabled` (`is_enabled`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COMMENT='SEO配置表';

#
# Data for table "fa_seo_config"
#

INSERT INTO `fa_seo_config` VALUES (1,'home','优质家教信息平台 - 专业家教服务，让学习更高效','家教,家教信息,一对一辅导,在线教育,优质教师,学习辅导,教育服务','专业的家教信息平台，汇聚优质教师资源，提供一对一辅导服务。覆盖全国多个城市，涵盖各科教学，帮助学生提高学习成绩，让学习更高效。','优质家教信息平台 - 专业家教服务','专业的家教信息平台，汇聚优质教师资源，提供一对一辅导服务。覆盖全国多个城市，涵盖各科教学。','','','index,follow',1.0,'daily',1,'2025-10-05 22:25:29','2025-10-05 22:25:29'),(2,'teachers','优秀教师推荐 - 精选优质家教教师','优秀教师,家教教师,教师推荐,一对一辅导,专业教师,教学经验','精选优质家教教师，拥有丰富教学经验和专业背景。涵盖各科教学，提供个性化辅导服务，帮助学生提高学习成绩。','优秀教师推荐 - 精选优质家教教师','精选优质家教教师，拥有丰富教学经验和专业背景。涵盖各科教学，提供个性化辅导服务。','','','index,follow',0.9,'weekly',1,'2025-10-05 22:25:29','2025-10-05 22:25:29'),(3,'teacher-detail','{teacher_name} - 专业{subject}家教教师','{teacher_name},{subject}家教,一对一辅导,专业教师,教学经验','{teacher_name}，{education}学历，{experience}年教学经验。专业教授{subject}，擅长{teaching_style}，帮助学生提高学习成绩。','{teacher_name} - 专业{subject}家教教师','{teacher_name}，{education}学历，{experience}年教学经验。专业教授{subject}，帮助学生提高学习成绩。','{teacher_photo}','','index,follow',0.8,'monthly',1,'2025-10-05 22:25:29','2025-10-05 22:25:29'),(4,'search','{keyword}家教信息 - 搜索结果','{keyword}家教,{keyword}辅导,一对一教学,专业教师','搜索{keyword}相关家教信息，找到合适的专业教师。提供一对一辅导服务，帮助学生提高{keyword}成绩。','{keyword}家教信息 - 搜索结果','搜索{keyword}相关家教信息，找到合适的专业教师。提供一对一辅导服务。','','','index,follow',0.7,'weekly',1,'2025-10-05 22:25:29','2025-10-05 22:25:29'),(5,'teacher-register','教师注册 - 加入我们成为优质家教教师','教师注册,家教教师,教师招聘,教育行业,教学工作','加入我们的教师团队，成为优质家教教师。提供灵活的工作时间和丰厚的报酬，让您的教学才能得到充分发挥。','教师注册 - 加入我们成为优质家教教师','加入我们的教师团队，成为优质家教教师。提供灵活的工作时间和丰厚的报酬。','','','index,follow',0.6,'monthly',1,'2025-10-05 22:25:29','2025-10-05 22:25:29'),(6,'city-light','点亮城市 - 助力城市开通家教服务','点亮城市,城市开通,家教服务,教育普及,城市发展','参与城市点亮活动，助力更多城市开通优质家教服务。让每个城市的孩子都能享受到专业的教学辅导。','点亮城市 - 助力城市开通家教服务','参与城市点亮活动，助力更多城市开通优质家教服务。让每个城市的孩子都能享受到专业的教学辅导。','','','index,follow',0.7,'weekly',1,'2025-10-05 22:25:29','2025-10-05 22:25:29');

#
# Structure for table "fa_service_agreement"
#

DROP TABLE IF EXISTS `fa_service_agreement`;
CREATE TABLE `fa_service_agreement` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '协议ID',
  `title` varchar(100) NOT NULL COMMENT '协议标题',
  `content` text NOT NULL COMMENT '协议内容',
  `version` varchar(20) DEFAULT '1.0' COMMENT '版本号',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用：0-否，1-是',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COMMENT='服务协议表';

#
# Data for table "fa_service_agreement"
#

INSERT INTO `fa_service_agreement` VALUES (1,'家教服务支付协议','<div style=\"line-height: 1.8;\">\n<h3>一、服务说明</h3>\n<p>1. 本平台为家长与教师提供信息发布服务。</p>\n<p>2. 支付费用为信息服务费，不包含实际家教授课费用。</p>\n<p>3. 支付成功后，系统将提供家长联系方式。</p>\n\n<h3>二、支付说明</h3>\n<p>1. 支付前请仔细核对订单信息。</p>\n<p>2. 支付金额一经支付，不予退还。</p>\n<p>3. 支持微信支付、支付宝支付。</p>\n\n<h3>三、服务承诺</h3>\n<p>1. 保证提供的联系方式真实有效。</p>\n<p>2. 如信息错误，可联系客服处理。</p>\n<p>3. 保护用户隐私，不泄露个人信息。</p>\n\n<h3>四、免责声明</h3>\n<p>1. 本平台仅提供信息服务，不参与实际授课。</p>\n<p>2. 授课质量、费用结算等由家长与教师自行协商。</p>\n<p>3. 因授课产生的纠纷，由双方自行解决。</p>\n\n<h3>五、其他</h3>\n<p>1. 本协议最终解释权归本平台所有。</p>\n<p>2. 如有疑问，请联系客服。</p>\n</div>','1.0',1,'2025-10-04 16:56:57','2025-10-04 17:13:27');

#
# Structure for table "fa_site_banners"
#

DROP TABLE IF EXISTS `fa_site_banners`;
CREATE TABLE `fa_site_banners` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `banner_scene` varchar(64) NOT NULL DEFAULT 'default' COMMENT '展示场景：default=网站通用轮播，parent_mini_home=小程序家长端首页',
  `title` varchar(200) DEFAULT '' COMMENT '横幅标题',
  `description` text COMMENT '横幅描述',
  `image_url` varchar(500) NOT NULL COMMENT '横幅图片URL',
  `link_url` varchar(500) DEFAULT '' COMMENT '点击跳转链接',
  `target` varchar(20) DEFAULT '_self' COMMENT '链接打开方式：_self=当前窗口, _blank=新窗口',
  `sort_order` int(11) DEFAULT '0' COMMENT '排序值（越小越靠前）',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态：1=启用，0=禁用',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_sort_status` (`sort_order`,`status`),
  KEY `idx_banner_scene_status` (`banner_scene`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COMMENT='网站横幅表';

