INSERT INTO `fa_success_cases` VALUES (1,'初中','语文','成绩进步','[\"\\/uploads\\/lead\\/20260408\\/69d5d240804ff.png\"]','从及格到优秀：初中语文 20 分提升全记录','定制初中语文专项辅导，覆盖基础、阅读、作文全模块，针对性查漏补缺，高效提分。','初一学生，语文基础薄弱，成绩徘徊在及格线，阅读、作文失分严重，学习信心不足。','经系统辅导，语文成绩提升 20 分，基础扎实、阅读答题规范、作文水平显著提高，重拾学习信心。','孩子语文进步巨大，感谢老师专业辅导，学习状态越来越好！',0,1,'2026-04-08 11:59:13','2026-04-08 11:59:13');

#
# Structure for table "fa_teacher_accounts"
#

DROP TABLE IF EXISTS `fa_teacher_accounts`;
CREATE TABLE `fa_teacher_accounts` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '账号ID',
  `teacher_id` int(11) DEFAULT NULL COMMENT '关联的教师ID',
  `email` varchar(100) NOT NULL COMMENT '邮箱',
  `password` varchar(255) NOT NULL COMMENT '密码（加密）',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态：0=未验证，1=已验证，2=已禁用',
  `last_login_time` int(11) DEFAULT NULL COMMENT '最后登录时间',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `email` (`email`),
  KEY `teacher_id` (`teacher_id`),
  KEY `status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COMMENT='教师账号表';

