INSERT INTO `fa_teachers` VALUES (11,1000,NULL,'张教授','男','13800138001',NULL,'zhang@example.com',NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'博士','清华大学','数学与应用数学',NULL,NULL,NULL,200.00,NULL,'数学,高等数学,线性代数',NULL,'海淀区,朝阳区','清华大学数学系博士毕业，从事数学教学15年，曾获得全国优秀教师称号。','我是张教授，清华大学数学系博士，拥有15年丰富教学经验。我热爱数学教育，善于将复杂的数学概念用简单易懂的方式讲解。',NULL,NULL,'[\"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=300&h=300&fit=crop&crop=face\"]','active',0,0,0,NULL,NULL,NULL,NULL,'approved','2025-12-29 11:52:48',NULL,0,NULL,'2025-10-06 00:31:09','2026-03-12 13:30:58',NULL,NULL,NULL),(12,1001,NULL,'李老师','女','13800138002',NULL,'li@example.com',NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'硕士','北京外国语大学','英语语言文学',NULL,NULL,NULL,150.00,NULL,'英语,雅思,托福',NULL,'西城区,东城区','北京外国语大学英语系硕士，英语专业八级，雅思8.5分。从事英语教学12年。','大家好，我是李老师，北外英语系硕士毕业。我热爱英语教学，拥有12年丰富经验。',NULL,NULL,'[\"https://images.unsplash.com/photo-1494790108755-2616b612b786?w=300&h=300&fit=crop&crop=face\"]','active',0,0,0,NULL,NULL,NULL,NULL,'approved','2025-12-29 11:52:48',NULL,0,NULL,'2025-10-06 00:31:09','2026-03-13 11:24:53',NULL,NULL,NULL),(13,1002,NULL,'王老师','男','13800138003',NULL,'wang@example.com',NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'硕士','北京大学','物理学',NULL,NULL,NULL,180.00,NULL,'物理,高中物理,大学物理',NULL,'海淀区,丰台区','北京大学物理系硕士，物理教学10年经验。擅长初高中物理教学。','我是王老师，北大物理系硕士，拥有10年物理教学经验。我善于用实验和生活中的例子来解释物理现象。',NULL,NULL,'[\"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=300&h=300&fit=crop&crop=face\"]','active',0,0,0,NULL,NULL,NULL,NULL,'approved','2025-12-29 11:52:48',NULL,0,NULL,'2025-10-06 00:31:09','2026-03-12 13:30:58',NULL,NULL,NULL),(14,1003,NULL,'陈老师','女','13800138004',NULL,'chen@example.com',NULL,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'本科','北京师范大学','化学',NULL,NULL,NULL,120.00,NULL,'化学,高中化学',NULL,'朝阳区,通州区','北京师范大学化学系本科，化学教学8年经验。','我是陈老师，北师大化学系毕业，拥有8年化学教学经验。我注重培养学生的实验能力和化学思维。',NULL,NULL,'[\"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=300&h=300&fit=crop&crop=face\"]','active',0,0,0,NULL,NULL,NULL,NULL,'ap